<?php declare(ticks=1000); $start = time(); register_tick_function(function() use ($start) { if (time() - $start >= 5) { $trace = debug_backtrace(DEBUG_BACKTRACE_IGNORE_ARGS); $output = ''; foreach ($trace as $t) { $output .= ($t['file'] ?? '') . ':' . ($t['line'] ?? '') . ' - ' . ($t['class'] ?? '') . ($t['type'] ?? '') . ($t['function'] ?? '') . PHP_EOL; } file_put_contents('hang_trace.txt', $output); exit; } }); require 'vendor/autoload.php'; $app = require_once 'bootstrap/app.php'; $kernel = $app->make(Illuminate\Contracts\Http\Kernel::class); $request = Illuminate\Http\Request::create('/dashboard', 'GET'); $response = $kernel->handle($request);
